+
+    // Show capability prompt.
+    let request = ExtensionUiRequest::new(
+        "cap-block",
+        "confirm",
+        json!({
+            "extension_id": "test-ext",
+            "capability": "exec",
+            "message": "test",
+        }),
+    );
+    apply_pi(
+        &harness,
+        &mut app,
+        "PiMsg::ExtensionUiRequest(capability)",
+        PiMsg::ExtensionUiRequest(request),
